import json
import csv
import sys
from pathlib import Path
from typing import Dict, Any, List, Optional
from collections import defaultdict

# Import project utilities
from utils.logging import get_logger, log_stage_start, log_stage_end, log_resource_usage

logger = get_logger(__name__)

VALID_FAILURE_TYPES = [
    "Syntactic",
    "Logical",
    "Semantic",
    "Missing Context",
    "Unstructured"
]

def load_results_csv(csv_path: Path) -> List[Dict[str, Any]]:
    """Load the results CSV file generated by run_experiments.py."""
    if not csv_path.exists():
        raise FileNotFoundError(f"Results file not found: {csv_path}")
    
    rows = []
    with open(csv_path, 'r', newline='', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        for row in reader:
            rows.append(row)
    return rows

def calculate_stratified_rates(
    results: List[Dict[str, Any]],
    failure_types: List[str]
) -> Dict[str, Dict[str, float]]:
    """
    Calculate 'Success Rate of First Pivot' stratified by failure type.
    
    Returns a dictionary mapping failure_type -> {
        'total': int,
        'successes': int,
        'rate': float
    }
    """
    # Initialize counters for each failure type
    stats: Dict[str, Dict[str, int]] = {
        ft: {"total": 0, "successes": 0} 
        for ft in failure_types
    }
    
    # Also track an "Unknown" category for any unexpected failure types
    unknown_stats = {"total": 0, "successes": 0}
    
    for row in results:
        failure_type = row.get("failure_type", "").strip()
        success_val = row.get("success", "").strip()
        
        # Parse success (expecting '1', 'True', 'true', or '0', 'False', 'false')
        is_success = False
        if success_val.lower() in ("1", "true", "t", "yes"):
            is_success = True
        elif success_val.lower() in ("0", "false", "f", "no"):
            is_success = False
        else:
            # Try to parse as integer
            try:
                is_success = int(success_val) == 1
            except (ValueError, TypeError):
                logger.warning(f"Could not parse success value: {success_val} for row: {row}")
                continue
        
        # Determine which bucket to use
        if failure_type in stats:
            bucket = stats[failure_type]
        else:
            bucket = unknown_stats
        
        bucket["total"] += 1
        if is_success:
            bucket["successes"] += 1
    
    # Calculate rates
    rates: Dict[str, Dict[str, float]] = {}
    
    for ft in failure_types:
        s = stats[ft]
        rate = 0.0
        if s["total"] > 0:
            rate = s["successes"] / s["total"]
        rates[ft] = {
            "total": s["total"],
            "successes": s["successes"],
            "rate": rate
        }
    
    if unknown_stats["total"] > 0:
        rate = 0.0
        if unknown_stats["total"] > 0:
            rate = unknown_stats["successes"] / unknown_stats["total"]
        rates["Unknown"] = {
            "total": unknown_stats["total"],
            "successes": unknown_stats["successes"],
            "rate": rate
        }
    
    return rates

def write_stratified_rates_csv(
    rates: Dict[str, Dict[str, float]],
    output_path: Path
) -> None:
    """
    Write the stratified rates to a CSV file.
    
    Format:
    failure_type,total,successes,rate
    Syntactic,10,8,0.8
    ...
    """
    output_path.parent.mkdir(parents=True, exist_ok=True)
    
    with open(output_path, 'w', newline='', encoding='utf-8') as f:
        writer = csv.writer(f)
        writer.writerow(["failure_type", "total", "successes", "rate"])
        
        # Sort by failure type for consistent output
        for ft in sorted(rates.keys()):
            data = rates[ft]
            writer.writerow([
                ft,
                data["total"],
                data["successes"],
                f"{data['rate']:.4f}"
            ])

def save_stratified_rates_json(
    rates: Dict[str, Dict[str, float]],
    json_path: Path
) -> None:
    """Save the raw rate dictionary to a JSON file for downstream use."""
    json_path.parent.mkdir(parents=True, exist_ok=True)
    with open(json_path, 'w', encoding='utf-8') as f:
        json.dump(rates, f, indent=2)

def main() -> None:
    """
    Main entry point for calculating stratified success rates.
    
    Reads: data/derived/results.csv
    Writes: data/derived/stratified_success_rates.csv, data/derived/stratified_rates.json
    """
    log_stage_start("calculate_stratified_rates")
    log_resource_usage()
    
    project_root = Path(__file__).resolve().parent.parent.parent
    results_path = project_root / "data" / "derived" / "results.csv"
    output_csv_path = project_root / "data" / "derived" / "stratified_success_rates.csv"
    output_json_path = project_root / "data" / "derived" / "stratified_rates.json"
    
    logger.info(f"Loading results from: {results_path}")
    try:
        results = load_results_csv(results_path)
    except FileNotFoundError as e:
        logger.error(f"Failed to load results: {e}")
        sys.exit(1)
    
    logger.info(f"Loaded {len(results)} result rows.")
    
    logger.info("Calculating stratified success rates...")
    rates = calculate_stratified_rates(results, VALID_FAILURE_TYPES)
    
    # Log summary
    for ft, data in rates.items():
        logger.info(f"  {ft}: {data['successes']}/{data['total']} ({data['rate']:.2%})")
    
    logger.info(f"Writing CSV to: {output_csv_path}")
    write_stratified_rates_csv(rates, output_csv_path)
    
    logger.info(f"Writing JSON to: {output_json_path}")
    save_stratified_rates_json(rates, output_json_path)
    
    log_stage_end("calculate_stratified_rates")
    logger.info("Stratified success rates calculation complete.")

if __name__ == "__main__":
    main()